// 三载体一致:纯 JS,无 DOM/uplink/shadow 足迹
import xirr from 'https://cdn.jsdelivr.net/npm/xirr@1/+esm';               // default 导出函数
// 字段是 when(Date)不是 date;金额须正负混合(流出为负、现值/流入为正)
const txns = data.transactions.map(t => ({ amount: t.amount, when: new Date(t.when) }));
let rate;
try { rate = xirr(txns, data.guess != null ? { guess: data.guess } : undefined); }
catch (e) { rate = null; /* 全同号/少于两笔/同日/不收敛都会抛错 */ }
// rate = 年化 IRR 小数(如 0.25 = 25%)
